mapper.select:
SELECT cr.CR_NO AS crNo, /* 제의번호 */ cr.DRAWING_NO AS drawingNo, /* 도번 */ cr.REV_NO AS revNo, /* REV */ cr.CR_TITLE_NM AS crTitleNm, /* 제목 */ cr.CR_TYPE_CD AS crTypeCd, /* 제의사유 */ FN_GET_CD_NM('crTypeCd', cr.CR_TYPE_CD, #{sessionLang}) AS crTypeDesc, cr.PURCHASER_UID AS purchaserUid, /* 구매담당자 */ purchaser.USER_NM AS purchaserUserNm, /* 구매담당자 */ req.INSERT_DT AS requestDt, /* 요청일 */ req.APPROVAL_DT AS approvalDt, /* 결재일 */ req.STATUS_CD AS statusCd, /* 진행상태 */ cr.STATUS_CD AS crStatusCd, /* cr 상태 */ FN_GET_CD_NM('crRequestStatusCd', req.STATUS_CD, #{sessionLang}) AS statusNm, FN_GET_CD_NM('crStatusCd', cr.STATUS_CD, #{sessionLang}) AS crStatusNm, cr.BUSINESS_AREA_CD AS businessAreaCd, /* 사업장 */ FN_GET_CD_NM('businessAreaCd', cr.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, COALESCE(cr.PRODUCT_NO, '') AS productNm, /* 기종 */ cr.PRODUCT_NO AS productNo, /* 기종 */ (SELECT COMPANY_NM FROM DOCS_COMPANY tmp WHERE tmp.BIZ_NO = cr.VENDOR_NO) AS vendorNm, /* 업체코드 */ cr.VENDOR_NO AS vendorNo, /* 업체(사업자번호) */ (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = cr.VENDOR_UID) AS vendorUserNm, /* 업체요청자 */ cr.VENDOR_UID AS vendorUid /* 업체요청자 */ FROM ITN_CR cr INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON cr.CR_NO = reqMapping.OBJECT_ID INNER JOIN DOCS_REQUEST req ON req.REQUEST_NO = reqMapping.REQUEST_NO INNER JOIN DOCS_USER purchaser ON purchaser.USER_ID = cr.PURCHASER_UID INNER JOIN DOCS_REQUEST_DETAIL currDetail ON currDetail.REQUEST_NO = req.REQUEST_NO AND currDetail.PROCESS_SEQ = req.CURRENT_PROCESS_SEQ_NO WHERE currDetail.APPROVAL_STATUS_CD = 'ACCEPT'
AND req.INSERT_DT BETWEEN #{requestStartDt}::DATE AND (#{requestEndDt}::DATE + INTERVAL '1 DAY')
AND cr.VENDOR_NO = #{vendorNo}
AND cr.PURCHASER_UID = #{purchaserUid}
AND cr.STATUS_CD = #{crStatusCd}
AND cr.BUSINESS_AREA_CD = #{businessAreaCd}
ORDER BY req.INSERT_DT DESC, cr.CR_NO DESC
ORDER BY ${sortColumn} ${order}, cr.CR_NO ${order}
LIMIT #{end} OFFSET #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT cr.CR_NO AS crNo /* 제의번호 */ , cr.DRAWING_NO AS drawingNo /* 도번 */ , cr.REV_NO AS revNo /* REV */ , cr.CR_TITLE_NM AS crTitleNm /* 제목 */ , cr.CR_TYPE_CD AS crTypeCd /* 제의사유 */ , FN_GET_CD_NM('crTypeCd', cr.CR_TYPE_CD, #{sessionLang}) AS crTypeDesc , cr.PURCHASER_UID AS purchaserUid /* 구매담당자 */ , purchaser.USER_NM AS purchaserUserNm /* 구매담당자 */ , req.INSERT_DT AS requestDt /* 요청일 */ , req.APPROVAL_DT AS approvalDt /* 결재일 */ , req.STATUS_CD AS statusCd /* 진행상태 */ , cr.STATUS_CD AS crStatusCd /* cr 상태 */ , FN_GET_CD_NM('crRequestStatusCd', req.STATUS_CD, #{sessionLang}) AS statusNm , FN_GET_CD_NM('crStatusCd', cr.STATUS_CD, #{sessionLang}) AS crStatusNm , cr.BUSINESS_AREA_CD AS businessAreaCd /* 사업장 */ , FN_GET_CD_NM('businessAreaCd', cr.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm , COALESCE(cr.PRODUCT_NO, '') AS productNm /* 기종 */ , cr.PRODUCT_NO AS productNo /* 기종 */ , ( SELECT COMPANY_NM FROM DOCS_COMPANY tmp WHERE tmp.BIZ_NO = cr.VENDOR_NO ) AS vendorNm /* 업체코드 */ , cr.VENDOR_NO AS vendorNo /* 업체(사업자번호)*/ , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = cr.VENDOR_UID ) AS vendorUserNm /* 업체요청자*/ , cr.VENDOR_UID AS vendorUid /* 업체요청자 */ FROM ITN_CR cr INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON cr.CR_NO = reqMapping.OBJECT_ID INNER JOIN DOCS_REQUEST req ON req.REQUEST_NO = reqMapping.REQUEST_NO INNER JOIN DOCS_USER purchaser ON purchaser.USER_ID = cr.PURCHASER_UID INNER JOIN DOCS_REQUEST_DETAIL currDetail ON currDetail.REQUEST_NO = req.REQUEST_NO AND currDetail.PROCESS_SEQ = req.CURRENT_PROCESS_SEQ_NO WHERE currDetail.APPROVAL_STATUS_CD = 'ACCEPT'
AND req.INSERT_DT BETWEEN #{requestStartDt}::DATE AND (#{requestEndDt}::DATE + INTERVAL '1 DAY')
) A1 WHERE 1=1
AND vendorNo = #{vendorNo}
AND purchaserUid = #{purchaserUid}
AND crStatusCd = #{crStatusCd}
AND businessAreaCd = #{businessAreaCd}
) B1

mapper.update:
UPDATE DOCS_REQUEST_DETAIL
SET ACTION_DT = CURRENT_TIMESTAMP
  , REQUEST_DESC = #{requestDesc}
  , ACTION_CD = #{actionCd}
WHERE REQUEST_NO = (SELECT REQUEST_NO FROM DOCS_REQUEST_MAPPING WHERE OBJECT_ID = #{crNo} LIMIT 1)
  AND APPROVAL_STATUS_CD = 'ACCEPT'

UPDATE DOCS_REQUEST_DETAIL
SET ACTION_DT = CURRENT_TIMESTAMP
  , ORIGINAL_USER_CD = #{sessionUser.teamLeaderUid}
  , ACTUAL_USER_CD = #{approvalUser}
  , APPROVAL_GRADE_CD = #{approvalGradeCd}
WHERE REQUEST_NO = (SELECT REQUEST_NO FROM DOCS_REQUEST_MAPPING WHERE OBJECT_ID = #{crNo} LIMIT 1)
  AND APPROVAL_STATUS_CD = 'APPROVAL'

UPDATE DOCS_REQUEST
SET STATUS_CD = #{actionCd}

	, CURRENT_PROCESS_SEQ_NO = #{currentProcessSeqNo}

, UPDATE_DT = CURRENT_TIMESTAMP
, UPDATE_USER_CD = #{sessionUser.userCd}
WHERE REQUEST_NO = (SELECT REQUEST_NO FROM DOCS_REQUEST_MAPPING WHERE OBJECT_ID = #{crNo} LIMIT 1)

UPDATE ITN_CR
SET REVIEW_RESULT = #{reviewResult}
, REJECT_REASON = #{rejectReason}
, PRODUCT_NO = #{productNo}
, STATUS_CD = #{statusCd}

	, MATERIAL_NO = #{materialNo}

WHERE CR_NO = #{crNo}
